

import type { URL } from 'url';

export interface DotenvParseOutput {
  [name: string]: string;
}

export interface DotenvPopulateOutput {
  [name: string]: string;
}


export function parse<T extends DotenvParseOutput = DotenvParseOutput>(
  src: string | Buffer
): T;

export interface DotenvConfigOptions {
  
  path?: string | string[] | URL;

  
  encoding?: string;

  
  quiet?: boolean;

  
  debug?: boolean;

  
  override?: boolean;

  
  processEnv?: DotenvPopulateInput;

  
  DOTENV_KEY?: string;
}

export interface DotenvConfigOutput {
  error?: DotenvError;
  parsed?: DotenvParseOutput;
}

type DotenvError = Error & {
  code:
    | 'MISSING_DATA'
    | 'INVALID_DOTENV_KEY'
    | 'NOT_FOUND_DOTENV_ENVIRONMENT'
    | 'DECRYPTION_FAILED'
    | 'OBJECT_REQUIRED';
}

export interface DotenvPopulateOptions {
  
  debug?: boolean;

  
  override?: boolean;
}

export interface DotenvPopulateInput {
  [name: string]: string | undefined;
}


export function config(options?: DotenvConfigOptions): DotenvConfigOutput;


export function configDotenv(options?: DotenvConfigOptions): DotenvConfigOutput;


export function populate(
  processEnv: DotenvPopulateInput,
  parsed: DotenvPopulateInput,
  options?: DotenvPopulateOptions
): DotenvPopulateOutput;


export function decrypt(encrypted: string, keyStr: string): string;
